package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import scala.util.Using
import java.io.File
import java.nio.charset.StandardCharsets
import java.nio.file.{Files, Paths}

@Singleton
class UserFilesController @Inject() (cc: ControllerComponents) extends AbstractController(cc) {

  private val uploadsDir = Paths.get("uploads").toAbsolutePath.normalize()

  def getFile(filename: String): Action[AnyContent] = Action { implicit request =>
    val decoded = java.net.URLDecoder.decode(filename, StandardCharsets.UTF_8.name())

    val resolved = uploadsDir.resolve(decoded).normalize()
    if (!resolved.startsWith(uploadsDir)) {
      Forbidden("Invalid path")
    } else if (!Files.exists(resolved) || !Files.isRegularFile(resolved)) {
      NotFound("File not found")
    } else {
      val file = resolved.toFile
      val bytes = Using.resource(Source.fromFile(file, "UTF-8")) { src =>
        src.mkString.getBytes(StandardCharsets.UTF_8)
      }
      val contentType = Option(Files.probeContentType(resolved)).getOrElse("application/octet-stream")
      Ok(bytes).as(contentType)
    }
  }
}